Here are the public test cases for feature14_snapshot_pruning:
{
  "description": "After a new snapshot deployment, removes deprecated snapshot build artifacts and leaves only metadata checksum files.",
  "cases": [
    {
      "input": {
        "action": "pruneSnapshotBuilds",
        "artifact_id": "artifact",
        "version_path": "group/artifact/1.0.0-R0.1-SNAPSHOT",
        "base_version": "1.0.0-R0.1",
        "old_builds": [
          "20220101.213700-1",
          "20220101.213701-2"
        ],
        "new_timestamp": "20220101.213702"
      },
      "expected_output": "remaining=group/artifact/1.0.0-R0.1-SNAPSHOT/maven-metadata.xml\nremaining=group/artifact/1.0.0-R0.1-SNAPSHOT/maven-metadata.xml.md5\nremaining=group/artifact/1.0.0-R0.1-SNAPSHOT/maven-metadata.xml.sha1\nremaining=group/artifact/1.0.0-R0.1-SNAPSHOT/maven-metadata.xml.sha256\nremaining=group/artifact/1.0.0-R0.1-SNAPSHOT/maven-metadata.xml.sha512\n"
